UIStoreDressDetail = class("UIStoreDressDetail", IGUILayout)

function UIStoreDressDetail:onLoad()
    self.btnClose = self:getChildWindow("StoreDressDetail-Close", GUIType.Button)
    self.actorActor = self:getChildWindow("StoreDressDetail-Actor", GUIType.ActorWindow)
    self.stName = self:getChildWindow("StoreDressDetail-Name", GUIType.StaticText)
    self.btnUse = self:getChildWindow("StoreDressDetail-Action-Use", GUIType.Button)
    self.btnBuy = self:getChildWindow("StoreDressDetail-Action-Buy", GUIType.Button)
    self.btnUnload = self:getChildWindow("StoreDressDetail-Action-Unload", GUIType.Button)
    self.layPrice = self:getChildWindow("StoreDressDetail-Price", GUIType.Layout)
    self.siPriceType = self:getChildWindow("StoreDressDetail-Price-Icon", GUIType.StaticImage)
    self.stPriceText = self:getChildWindow("StoreDressDetail-Price-Value", GUIType.StaticText)
    self.rotate = 1

    self:register()
    self:updateLanguage()
end

function UIStoreDressDetail:updateLanguage()
    self.btnUse:SetText(Lang:getString("dress_shop_use"))
    self.btnBuy:SetText(Lang:getString("shop_btn_buy"))
    self.btnUnload:SetText(Lang:getString("dress_shop_unload"))
end

function UIStoreDressDetail:onTick()
    self.actorActor:SetRotateY(self.actorActor:GetRotateY() + self.rotate)
end

function UIStoreDressDetail:register()

    self.actorActor:registerEvent(GUIEvent.TouchDown, function()
        self.rotate = 0
    end)

    self.actorActor:registerEvent(GUIEvent.TouchUp, function()
        self.rotate = 1
    end)

    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        GUIStoreDressDetail:hide()
    end)

    self.btnUse:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.Click)
        GamePacketSender:sendBedWarUseStoreDress(self.id)
        UIDressStore:changeStatue(self.id, 4)
        self:init(self.id)
    end)

    self.btnBuy:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.Click)
        if UIDressStore:getStatuesById(self.id) == 0 then
            return false
        end
        local config = DressConfig:findStoreDressById(self.id)
        local dress = UIDressStore:getDressData(self.id)
        local chip = 0
        if dress then
            chip = dress.Chip or 0
        end
        if config.Price <= chip then
            GamePacketSender:sendBedWarBuyStoreDress(self.id)
        else
            GUIDressStoreTip:setLackChipText(config.Price - chip, config.Name, config.Id)
            GUIDressStoreTip:show()
        end
    end)

    self.btnUnload:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.Click)
        GamePacketSender:sendBedWarUnloadStoreDress(self.id)
        UIDressStore:changeStatue(self.id, 3)
        self:init(self.id)
    end)

    self:registerDataCallBack("LackChip", function(data)
        local config = DressConfig:findStoreDressById(data.Id)
        GUIDressStoreTip:setLackChipText(data.lackNum, config.Name, config.Id)
        GUIDressStoreTip:show()
    end, JsonBuilderProcessor)
end

function UIStoreDressDetail:init(id, chip)
    self.id = id
    local statue = UIDressStore:getStatuesById(id)
    local config = DressConfig:findStoreDressById(id)
    self.stName:SetText(Lang:getString(config.Name))
    self.actorActor:SetActor1(config.Actor, "idle", 0)
    self.actorActor:UseBodyPart("body", config.BodyId)
    self.actorActor:SetEnabled(true)
    if statue == 1 or statue == 2 then
        self.btnUse:SetVisible(false)
        self.btnUnload:SetVisible(false)
        self.btnBuy:SetVisible(true)
        self.layPrice:SetVisible(true)
        self.btnBuy:SetArea({ 0, 75 }, { 0, -26 }, { 0.25, 0 }, { 0.11, 0 })
        self.siPriceType:SetImage(config.ChipImg)
        self.stPriceText:SetText(chip .. "/" .. config.Price)
    elseif statue == 3 then
        self.btnUse:SetVisible(true)
        self.btnUse:SetArea({ 0, 0 }, { 0, -26 }, { 0.25, 0 }, { 0.11, 0 })
        self.btnUnload:SetVisible(false)
        self.btnBuy:SetVisible(false)
        self.layPrice:SetVisible(false)
    elseif statue == 4 or statue == 5 then
        self.btnUse:SetVisible(false)
        self.btnUnload:SetVisible(true)
        self.btnUnload:SetArea({ 0, 0 }, { 0, -26 }, { 0.25, 0 }, { 0.11, 0 })
        self.btnBuy:SetVisible(false)
        self.layPrice:SetVisible(false)
    end
    GUIStoreDressDetail:show()
end

return UIStoreDressDetail